// LazusAI inbound handler — one parameterized instance for every client.
// Pipeline: voice transcription -> identify sender (staff vs customer) ->
// load config -> RAG context -> build prompt -> NIM (DeepSeek->Kimi->GLM->
// Mistral) -> booking tool-loop (availability / create booking via Core API)
// -> escalation check -> reply via BlueBubbles -> log turn.
// All AI endpoints are local (no external AI APIs).

const http = this.helpers.httpRequest;
const env = (k, d='') => ($env[k] ?? d);
const CORE = env('CORE_API_URL', 'http://127.0.0.1:8003').replace(/\/$/, '');
const NIM = env('NIM_BASE_URL', 'http://127.0.0.1:8000').replace(/\/$/, '');
const WHISPER = env('WHISPER_URL', 'http://127.0.0.1:8002').replace(/\/$/, '');
const BB = env('BLUEBUBBLES_URL', '').replace(/\/$/, '');
const BB_PW = env('BLUEBUBBLES_PASSWORD', '');
const KEY = env('LAZUSAI_CORE_KEY', '');
const hdr = { 'X-LazusAI-Key': KEY, 'Content-Type': 'application/json' };

const inItem = $input.first().json;
const clientId = (inItem.params && inItem.params.client_id) || inItem.client_id;
const body = inItem.body || inItem;
let messageText = body.message || '';
const sender = body.sender || '';
const chatGuid = body.chat_guid || '';

// Business-local "today" for booking date math (override with TZ_OFFSET_MIN).
const tzMin = parseInt(env('TZ_OFFSET_MIN', '0'), 10) || 0;
const nowLocal = new Date(Date.now() + tzMin * 60000);
const todayISO = nowLocal.toISOString().slice(0, 10);

// 1. Voice note -> Whisper transcription.
if (body.voice_note) {
  const audio = (body.attachments || []).find(a => a.is_audio) || {};
  let url = audio.url || '';
  if (url.startsWith('/') && BB) url = BB + url;
  const tr = await http({ method: 'POST', url: WHISPER + '/transcribe',
    headers: hdr, body: { url, filename: audio.name || 'audio.m4a' }, json: true });
  messageText = (tr && tr.text) || messageText;
}

// 2. Load client config.
const cfg = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/config`, headers: hdr, json: true });
if (cfg.active === false) {
  return [{ json: { skipped: true, reason: 'inactive', client_id: clientId } }];
}

// 2b. Identify the sender — staff numbers get a different persona.
let who = { role: 'customer' };
try {
  who = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/identify?phone=${encodeURIComponent(sender)}`, headers: hdr, json: true });
} catch (e) { /* default to customer */ }
const isStaff = who.role === 'staff';

// 3. RAG: last 10 turns for continuity.
const feed = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/feed?limit=10`, headers: hdr, json: true });
const recent = (feed.turns || []).map(t => ({ role: t.role === 'assistant' ? 'assistant' : 'user', content: t.text }));

// Build a compact business-context block from config.
const ctxLines = [];
if (cfg.services && cfg.services.length) ctxLines.push('Services: ' + cfg.services.join(', '));
if (cfg.pricing) ctxLines.push('Pricing: ' + Object.entries(cfg.pricing).map(([k,v])=>`${k}: ${v}`).join('; '));
if (cfg.hours) ctxLines.push('Hours: ' + Object.entries(cfg.hours).map(([k,v])=>`${k} ${v}`).join('; '));
if (cfg.faqs) cfg.faqs.forEach(f => ctxLines.push(`FAQ — ${f.q} ${f.a}`));
const contextBlock = ctxLines.join('\n');

// 3b. Booking context + protocol (only when the client enabled booking).
const bookingOn = !!cfg.booking_enabled;
let bookingBlock = '';
if (bookingOn) {
  const matrix = (cfg.services_matrix || []).map(s => {
    const bits = [s.name];
    if (s.price != null) bits.push(`$${s.price}`);
    if (s.duration_min) bits.push(`${s.duration_min}min`);
    if (s.staff && s.staff.length) bits.push('by ' + s.staff.join('/'));
    return '• ' + bits.join(' — ');
  }).join('\n');
  const team = (cfg.staff || []).map(s => s.name + (s.role ? ` (${s.role})` : '')).join(', ');
  const pay = ((cfg.integrations || {}).payment) || {};
  let payNote = '';
  if (pay.model === 'deposit') payNote = `A deposit of $${pay.deposit_amount || 0} is required; a payment link will be sent automatically after booking.`;
  else if (pay.model === 'full') payNote = 'Full payment is collected via a link sent automatically after booking.';

  bookingBlock = [
    `\nBOOKING IS ENABLED. Today is ${todayISO}.`,
    matrix ? `Bookable services:\n${matrix}` : '',
    team ? `Team: ${team}` : '',
    payNote,
    `\nTo help a customer book, gather: service, preferred day (resolve to a YYYY-MM-DD date), optional staff, their name, and phone.`,
    `When you need to see open times, end your reply with EXACTLY one line:`,
    `[[AVAIL service="<name>" date="<YYYY-MM-DD>" staff="<name or empty>"]]`,
    `When the customer has confirmed a specific service, date, time, and given their name, end your reply with EXACTLY one line:`,
    `[[BOOK service="<name>" staff="<name or empty>" date="<YYYY-MM-DD>" start="<HH:MM 24h>" name="<customer name>" phone="${sender}" notes="<optional>"]]`,
    `Never invent open times — only offer times returned by an AVAIL result. Do not show the [[...]] line's raw text as the whole message; put your normal reply first, then the directive on its own final line.`,
  ].filter(Boolean).join('\n');
}

// 4. System prompt (customer vs staff persona).
let systemPrompt;
if (isStaff) {
  const mine = bookingOn ? await http({ method: 'GET',
    url: `${CORE}/clients/${clientId}/bookings?date=${todayISO}${who.name ? `&staff=${encodeURIComponent(who.name)}` : ''}`,
    headers: hdr, json: true }).catch(() => ({ bookings: [] })) : { bookings: [] };
  const list = (mine.bookings || []).map(b => `${b.start} ${b.service} — ${b.customer_name || b.customer_phone || ''} (${b.status})`).join('\n') || 'nothing booked yet';
  systemPrompt = `You are the LazusAI staff assistant for ${cfg.business_name}. You are talking to ${who.name || 'a team member'}${who.staff_role ? ` (${who.staff_role})` : ''}, a STAFF member — not a customer. Be brief and helpful.\nToday's schedule for them (${todayISO}):\n${list}\n\nYou can answer questions about their day and the business. If they ask to change a booking, tell them to use the dashboard for now.${bookingBlock}`;
} else {
  systemPrompt = `You are the iMessage assistant for ${cfg.business_name} (${cfg.industry}).\nPersonality & rules: ${cfg.ai_personality}\n\nBusiness context:\n${contextBlock}\n${bookingBlock}\n\nAnswer as the business. Be concise (SMS-length). If you cannot help, offer to have the owner follow up and capture the customer's name and contact details.`;
}

const chain = [
  env('NIM_MODEL_DEEPSEEK', 'deepseek-ai/deepseek-r1'),
  env('NIM_MODEL_KIMI', 'moonshotai/kimi-k2'),
  env('NIM_MODEL_GLM', 'zhipuai/glm-5.2'),
  env('NIM_MODEL_MISTRAL', 'mistralai/mistral-large')
];
async function nim(messages) {
  for (const model of chain) {
    try {
      const r = await http({ method: 'POST', url: `${NIM}/v1/chat/completions`, headers: hdr,
        body: { model, messages, temperature: 0.4, max_tokens: 500 }, json: true });
      const txt = (((r.choices||[])[0]||{}).message||{}).content || '';
      if (txt.trim()) return { text: txt.trim(), model };
    } catch (e) { /* try next model */ }
  }
  return { text: '', model: '' };
}

// Directive parsing: [[VERB key="value" ...]]
function parseDirective(text) {
  const m = /\[\[(AVAIL|BOOK)\b([^\]]*)\]\]/i.exec(text);
  if (!m) return null;
  const verb = m[1].toUpperCase();
  const args = {};
  const re = /(\w+)\s*=\s*"([^"]*)"/g; let a;
  while ((a = re.exec(m[2])) !== null) args[a[1]] = a[2];
  return { verb, args, raw: m[0] };
}
const stripDirective = t => t.replace(/\[\[(AVAIL|BOOK)\b[^\]]*\]\]/gi, '').trim();

// 5. First model pass.
let messages = [{ role: 'system', content: systemPrompt }, ...recent, { role: 'user', content: messageText }];
let { text: reply, model: usedModel } = await nim(messages);
let bookingResult = null;

// 6. Booking tool-loop (max 2 iterations).
for (let i = 0; bookingOn && i < 2; i++) {
  const d = parseDirective(reply);
  if (!d) break;
  let toolMsg = '';
  if (d.verb === 'AVAIL') {
    const qs = `date=${encodeURIComponent(d.args.date||todayISO)}&service=${encodeURIComponent(d.args.service||'')}${d.args.staff?`&staff=${encodeURIComponent(d.args.staff)}`:''}`;
    let av = { slots: [] };
    try { av = await http({ method: 'GET', url: `${CORE}/clients/${clientId}/availability?${qs}`, headers: hdr, json: true }); } catch (e) {}
    const slots = (av.slots || []).slice(0, 8).map(s => s.start + (s.staff ? ` (${s.staff})` : '')).join(', ');
    toolMsg = slots ? `AVAIL result for ${d.args.service} on ${d.args.date}: ${slots}. Offer these to the customer.` :
      `AVAIL result: no open slots for ${d.args.service} on ${d.args.date}. Suggest another day.`;
  } else if (d.verb === 'BOOK') {
    try {
      const r = await http({ method: 'POST', url: `${CORE}/clients/${clientId}/bookings`, headers: hdr, json: true,
        body: { service: d.args.service, staff: d.args.staff || '', date: d.args.date, start: d.args.start,
                customer_name: d.args.name || '', customer_phone: d.args.phone || sender,
                notes: d.args.notes || '', source: 'bot' } });
      bookingResult = r;
      let extra = '';
      if (r.payment && r.payment.required && r.payment.url) {
        const label = r.payment.model === 'deposit' ? `deposit of $${r.payment.amount}` : `payment of $${r.payment.amount}`;
        extra = ` A ${label} holds the spot — pay here: ${r.payment.url}`;
      }
      toolMsg = `BOOK success: ${d.args.service} on ${d.args.date} at ${d.args.start}${d.args.staff?` with ${d.args.staff}`:''}. Confirm warmly to the customer.${extra ? ' Include this payment link verbatim in your reply:' + extra : ''}`;
    } catch (e) {
      const conflict = String(e && e.message || '').includes('409');
      toolMsg = conflict ? `BOOK failed: that time was just taken. Apologize and offer to check other times.`
                         : `BOOK failed due to a system error. Apologize and offer to have the team follow up.`;
    }
  }
  // Follow-up pass with the tool result so the model writes a natural reply.
  messages = [{ role: 'system', content: systemPrompt }, ...recent,
              { role: 'user', content: messageText },
              { role: 'assistant', content: reply },
              { role: 'system', content: toolMsg }];
  const nx = await nim(messages);
  reply = nx.text || reply; usedModel = nx.model || usedModel;
}
reply = stripDirective(reply);
if (!reply) reply = 'Thanks for your message! Someone from our team will get back to you shortly.';

// 7. Escalation keyword check.
const kws = (cfg.escalation_keywords || []).map(k => k.toLowerCase());
const hay = messageText.toLowerCase();
const escalated = !isStaff && kws.some(k => hay.includes(k));

// 8. Reply via BlueBubbles REST -> delivers over iMessage.
if (BB && chatGuid) {
  await http({ method: 'POST', url: `${BB}/api/v1/message/text`,
    qs: { password: BB_PW },
    body: { chatGuid, tempGuid: 'lazusai-' + Date.now(), message: reply, method: 'private-api' },
    json: true });
}

// 9. Log both turns.
await http({ method: 'POST', url: `${CORE}/clients/${clientId}/turns`, headers: hdr,
  body: { role: 'user', text: messageText, sender }, json: true });
await http({ method: 'POST', url: `${CORE}/clients/${clientId}/turns`, headers: hdr,
  body: { role: 'assistant', text: reply, sender }, json: true });

return [{ json: { client_id: clientId, sender, staff: isStaff, message: messageText, reply,
  model: usedModel, escalated, booked: !!bookingResult,
  booking_id: bookingResult && bookingResult.booking && bookingResult.booking.id,
  voice_note: !!body.voice_note } }];
